class PasswordStorageUtility {
    
    private let userDefaults = UserDefaults.standard
    private let passwordKey = "stored_password_hash"
    private let saltKey = "password_salt"
    
    func savePassword(_ password: String) -> Bool {
        let salt = generateSalt()
        guard let hash = hashPassword(password, salt: salt) else {
            return false
        }
        
        userDefaults.set(hash, forKey: passwordKey)
        userDefaults.set(salt, forKey: saltKey)
        userDefaults.synchronize()
        
        return true
    }
    
    func verifyPassword(_ password: String) -> Bool {
        guard let storedHash = userDefaults.string(forKey: passwordKey),
              let salt = userDefaults.string(forKey: saltKey) else {
            return false
        }
        
        guard let computedHash = hashPassword(password, salt: salt) else {
            return false
        }
        
        return computedHash == storedHash
    }
    
    func hasStoredPassword() -> Bool {
        return userDefaults.string(forKey: passwordKey) != nil
    }
    
    func clearPassword() {
        userDefaults.removeObject(forKey: passwordKey)
        userDefaults.removeObject(forKey: saltKey)
        userDefaults.synchronize()
    }
    
    private func hashPassword(_ password: String, salt: String) -> String? {
        let saltedPassword = password + salt
        
        guard let data = saltedPassword.data(using: .utf8) else {
            return nil
        }
        
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(data.count), &hash)
        }
        
        return hash.map { String(format: "%02x", $0) }.joined()
    }
    
    private func generateSalt() -> String {
        let length = 16
        var bytes = [UInt8](repeating: 0, count: length)
        let result = SecRandomCopyBytes(kSecRandomDefault, length, &bytes)
        
        if result == errSecSuccess {
            return bytes.map { String(format: "%02x", $0) }.joined()
        }
        
        var salt = ""
        for _ in 0..<length {
            let random = arc4random_uniform(256)
            salt += String(format: "%02x", random)
        }
        return salt
    }
}

